+  id: number;
+  backupId: number | null;
+  backupFile: string;
+  result: RestoreTestResult;
+  integrityCheck: string | null;
+  restoredRowCounts: Record<string, number> | null;
+  message: string | null;
+  testedAt: string;
+}
+
+interface BackupHeader {
+  version: 1;
+  algorithm: 'aes-256-gcm';
+  kdf: 'scrypt';
+  salt: string;
+  iv: string;
