+const KINDS: BackupKind[] = ['manual', 'auto', 'pre_restore'];
+const MAIN_TABLES = [
+  'business_profiles',
+  'products',
+  'subscription_plans',
+  'orders',
+  'order_items',
+  'invoices',
+  'audit_logs',
+  'backup_history',
