+++ b/packages/core/test/backup.test.ts
@@ -0,0 +1,131 @@
+import { createHash } from 'node:crypto';
+import { existsSync, mkdtempSync, readFileSync, rmSync, statSync } from 'node:fs';
+import { join } from 'node:path';
+import { tmpdir } from 'node:os';
+import { afterEach, describe, expect, it } from 'vitest';
+import { bootstrap } from '../src/db/bootstrap.js';
+import { openDb } from '../src/db/connection.js';
+import { createBackup, restoreBackup, runRestoreTest } from '../src/services/backup.js';
+
+let tempDirs: string[] = [];
+
+afterEach(() => {
+  for (const dir of tempDirs) {
+    rmSync(dir, { recursive: true, force: true });
+  }
+  tempDirs = [];
+});
+
+describe('encrypted local backup service', () => {
+  it('creates an encrypted backup and restores it to a separate database file', () => {
+    const dir = makeTempDir();
+    const dbPath = join(dir, 'free-worker.sqlite');
+    const outDir = join(dir, 'backups');
+    const restorePath = join(dir, 'restored.sqlite');
+
+    const db = bootstrap({ filename: dbPath });
+    seedProduct(db);
+    db.close();
+
+    const backup = createBackup(dbPath, 'correct horse battery staple', outDir);
+    expect(backup).toMatchObject({
+      id: expect.any(Number),
+      encrypted: true,
+      kind: 'manual',
+      sha256: expect.stringMatching(/^[0-9a-f]{64}$/),
+      sizeBytes: expect.any(Number),
+    });
+    expect(existsSync(backup.filePath)).toBe(true);
+    expect(backup.sizeBytes).toBe(statSync(backup.filePath).size);
+    expect(backup.sha256).toBe(createHash('sha256').update(readFileSync(backup.filePath)).digest('hex'));
+    expect(readFileSync(backup.filePath).equals(readFileSync(dbPath))).toBe(false);
+
+    const source = openDb({ filename: dbPath });
+    const history = source.prepare('SELECT sha256, size_bytes, encrypted, kind FROM backup_history').get() as {
+      sha256: string;
+      size_bytes: number;
+      encrypted: number;
+      kind: string;
+    };
+    source.close();
+    expect(history).toEqual({
+      sha256: backup.sha256,
+      size_bytes: backup.sizeBytes,
+      encrypted: 1,
+      kind: 'manual',
+    });
+
+    restoreBackup(backup.filePath, 'correct horse battery staple', restorePath);
+    const restored = openDb({ filename: restorePath });
+    try {
+      const product = restored.prepare('SELECT sku, title, price_tax_included FROM products').get() as {
+        sku: string;
+        title: string;
+        price_tax_included: number;
+      };
+      expect(product).toEqual({ sku: 'BK-001', title: 'バックアップ商品', price_tax_included: 3300 });
+    } finally {
+      restored.close();
+    }
+  });
+
+  it('records success and failure restore test logs without exposing the passphrase', () => {
+    const dir = makeTempDir();
+    const dbPath = join(dir, 'free-worker.sqlite');
+    const outDir = join(dir, 'backups');
+
+    const db = bootstrap({ filename: dbPath });
+    seedProduct(db);
+    db.close();
+
+    const backup = createBackup(dbPath, 'restore-test-passphrase', outDir);
+    const success = runRestoreTest(backup.filePath, 'restore-test-passphrase');
+    expect(success).toMatchObject({
+      backupId: backup.id,
+      result: 'success',
+      integrityCheck: 'ok',
+      restoredRowCounts: expect.objectContaining({ products: 1 }),
+    });
+
+    const failure = runRestoreTest(backup.filePath, 'wrong-passphrase');
+    expect(failure).toMatchObject({
+      backupId: backup.id,
+      result: 'failure',
+      integrityCheck: null,
+      restoredRowCounts: null,
+    });
+    expect(failure.message).not.toContain('wrong-passphrase');
+
+    const source = openDb({ filename: dbPath });
+    try {
+      const logs = source
+        .prepare('SELECT result, integrity_check, restored_row_counts, message FROM restore_test_logs ORDER BY id ASC')
+        .all() as Array<{
+        result: string;
+        integrity_check: string | null;
+        restored_row_counts: string | null;
+        message: string | null;
+      }>;
+      expect(logs).toHaveLength(2);
+      expect(logs[0]?.result).toBe('success');
+      expect(JSON.parse(logs[0]?.restored_row_counts ?? '{}')).toMatchObject({ products: 1 });
+      expect(logs[1]?.result).toBe('failure');
+      expect(logs[1]?.message).not.toContain('wrong-passphrase');
+    } finally {
+      source.close();
+    }
+  });
+});
+
+function makeTempDir(): string {
+  const dir = mkdtempSync(join(tmpdir(), 'free-worker-backup-'));
+  tempDirs.push(dir);
+  return dir;
+}
+
+function seedProduct(db: ReturnType<typeof bootstrap>): void {
+  db.prepare(
+    `INSERT INTO products (sku, title, product_type, price_tax_included)
+     VALUES (?, ?, ?, ?)`,
+  ).run('BK-001', 'バックアップ商品', 'download', 3300);
+}
diff --git a/packages/server/src/routes/backup.ts b/packages/server/src/routes/backup.ts
new file mode 100755
index 0000000000000000000000000000000000000000..6dc5f7506a66e9017af487f193b1d9301690f228
--- /dev/null
+++ b/packages/server/src/routes/backup.ts
@@ -0,0 +1,448 @@
+import { createCipheriv, createDecipheriv, createHash, randomBytes, scryptSync } from 'node:crypto';
+import { closeSync, existsSync, mkdirSync, openSync, readFileSync, renameSync, rmSync, statSync, writeSync } from 'node:fs';
+import { basename, dirname, join, resolve } from 'node:path';
+import { tmpdir } from 'node:os';
+import type { FastifyInstance } from 'fastify';
+import { migrate, openDb, type DB } from '@free-worker/core';
+
+type BackupKind = 'manual' | 'auto' | 'pre_restore';
+type RestoreTestResult = 'success' | 'failure';
+
+interface BackupPayload {
+  passphrase?: unknown;
+  outDir?: unknown;
+  kind?: unknown;
+  note?: unknown;
+}
+
+interface RestoreTestPayload {
+  filePath?: unknown;
+  passphrase?: unknown;
+}
+
+interface BackupHeader {
+  version: 1;
+  algorithm: 'aes-256-gcm';
+  kdf: 'scrypt';
+  salt: string;
+  iv: string;
+  sourceDbPath: string;
+  createdAt: string;
+}
+
+interface ParsedBackupFile {
+  header: BackupHeader;
+  ciphertext: Buffer;
+  authTag: Buffer;
+}
+
+interface BackupHistoryRow {
+  id: number;
+  file_path: string;
+  sha256: string;
+  size_bytes: number;
+  encrypted: number;
+  kind: BackupKind;
+  note: string | null;
+  created_at: string;
+}
+
+interface RestoreTestLogRow {
+  id: number;
+  backup_id: number | null;
+  backup_file: string;
+  result: RestoreTestResult;
+  integrity_check: string | null;
+  restored_row_counts: string | null;
+  message: string | null;
+  tested_at: string;
+}
+
+const MAGIC = Buffer.from('FWBKP001');
+const HEADER_LENGTH_BYTES = 4;
+const AUTH_TAG_BYTES = 16;
+const KEY_BYTES = 32;
+const SALT_BYTES = 32;
+const IV_BYTES = 12;
+const KINDS: BackupKind[] = ['manual', 'auto', 'pre_restore'];
+const MAIN_TABLES = [
+  'business_profiles',
+  'products',
+  'subscription_plans',
+  'orders',
+  'order_items',
+  'invoices',
+  'audit_logs',
+  'backup_history',
+  'restore_test_logs',
+];
+
+export async function backupRoutes(app: FastifyInstance): Promise<void> {
+  app.get('/api/backup', async () => {
+    return listHistory(app.db);
+  });
+
+  app.post('/api/backup', async (req, reply) => {
+    try {
+      const body = (req.body ?? {}) as BackupPayload;
+      const passphrase = normalizePassphrase(body.passphrase);
+      const kind = normalizeKind(body.kind);
+      const note = normalizeOptionalString(body.note);
+      const outDir = normalizeOptionalString(body.outDir) ?? join(app.config.dataDir, 'backups');
+      const backup = createRouteBackup(app.config.dbFile, passphrase, outDir, kind, note);
+      reply.code(201);
+      return backup;
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.post('/api/backup/restore-test', async (req, reply) => {
+    try {
+      const body = (req.body ?? {}) as RestoreTestPayload;
+      const filePath = normalizeRequiredString(body.filePath, 'filePath');
+      const passphrase = normalizePassphrase(body.passphrase);
+      return runRouteRestoreTest(filePath, passphrase);
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+}
+
+function createRouteBackup(
+  dbPath: string,
+  passphrase: string,
+  outDir: string,
+  kind: BackupKind,
+  note: string | null,
+): ReturnType<typeof mapBackupHistory> {
+  const sourceDbPath = resolve(dbPath);
+  if (!existsSync(sourceDbPath)) {
+    throw new Error('database file not found');
+  }
+  const backupDir = resolve(outDir);
+  mkdirSync(backupDir, { recursive: true });
+  checkpointDatabase(sourceDbPath);
+
+  const salt = randomBytes(SALT_BYTES);
+  const iv = randomBytes(IV_BYTES);
+  const cipher = createCipheriv('aes-256-gcm', deriveKey(passphrase, salt), iv);
+  const ciphertext = Buffer.concat([cipher.update(readFileSync(sourceDbPath)), cipher.final()]);
+  const backupPath = join(backupDir, `free-worker-${new Date().toISOString().replace(/[:.]/g, '-')}.sqlite.fwbak`);
+  writeBackupFile(
+    backupPath,
+    {
+      version: 1,
+      algorithm: 'aes-256-gcm',
+      kdf: 'scrypt',
+      salt: salt.toString('base64'),
+      iv: iv.toString('base64'),
+      sourceDbPath,
+      createdAt: new Date().toISOString(),
+    },
+    ciphertext,
+    cipher.getAuthTag(),
+  );
+
+  const sizeBytes = statSync(backupPath).size;
+  const sha256 = createHash('sha256').update(readFileSync(backupPath)).digest('hex');
+  const db = openDb({ filename: sourceDbPath });
+  try {
+    const row = db
+      .prepare(
+        `INSERT INTO backup_history (file_path, sha256, size_bytes, encrypted, kind, note)
+         VALUES (?, ?, ?, ?, ?, ?)
+         RETURNING *`,
+      )
+      .get(backupPath, sha256, sizeBytes, 1, kind, note) as BackupHistoryRow;
+    return mapBackupHistory(row);
+  } finally {
+    db.close();
+  }
+}
+
+function runRouteRestoreTest(file: string, passphrase: string): ReturnType<typeof mapRestoreTestLog> {
+  const backupFile = resolve(file);
+  let sourceDbPath: string | null = null;
+  let backupId: number | null = null;
+  let tempPath: string | null = null;
+
+  try {
+    const parsed = parseBackupFile(backupFile);
+    sourceDbPath = parsed.header.sourceDbPath;
+    backupId = findBackupId(sourceDbPath, backupFile);
+    tempPath = join(tmpdir(), `${basename(backupFile)}-${process.pid}-${Date.now()}-${randomBytes(4).toString('hex')}.sqlite`);
+    restoreRouteBackup(parsed, passphrase, tempPath);
+    const db = openDb({ filename: tempPath });
+    try {
+      migrate(db);
+      const integrityCheck = readIntegrityCheck(db);
+      if (integrityCheck !== 'ok') {
+        return recordRestoreTest(sourceDbPath, backupId, backupFile, 'failure', integrityCheck, null, integrityCheck);
+      }
+      return recordRestoreTest(sourceDbPath, backupId, backupFile, 'success', integrityCheck, countMainTables(db), null);
+    } finally {
+      db.close();
+    }
+  } catch (error) {
+    const message = error instanceof Error ? error.message : 'restore test failed';
+    return recordRestoreTest(sourceDbPath, backupId, backupFile, 'failure', null, null, message.replace(/\s+/g, ' ').slice(0, 500));
+  } finally {
+    if (tempPath) cleanupSqliteFiles(tempPath);
+  }
+}
+
+function listHistory(db: DB): ReturnType<typeof mapBackupHistory>[] {
+  return db
+    .prepare('SELECT * FROM backup_history ORDER BY id DESC')
+    .all()
+    .map((row) => mapBackupHistory(row as BackupHistoryRow));
+}
+
+function normalizePassphrase(value: unknown): string {
+  const passphrase = normalizeRequiredString(value, 'passphrase');
+  if (passphrase.length < 8) {
+    throw new Error('passphrase must be at least 8 characters');
+  }
+  return passphrase;
+}
+
+function normalizeRequiredString(value: unknown, field: string): string {
+  if (typeof value !== 'string' || value.trim() === '') {
+    throw new Error(`${field} is required`);
+  }
+  return value;
+}
+
+function normalizeOptionalString(value: unknown): string | null {
+  if (value == null) return null;
+  if (typeof value !== 'string') throw new Error('expected string');
+  const trimmed = value.trim();
+  return trimmed === '' ? null : trimmed;
+}
+
+function normalizeKind(value: unknown): BackupKind {
+  if (value == null) return 'manual';
+  if (typeof value !== 'string' || !KINDS.includes(value as BackupKind)) {
+    throw new Error('invalid kind');
+  }
+  return value as BackupKind;
+}
+
+function invalidPayload(error: unknown): { error: 'invalid_payload'; message: string } {
+  return {
+    error: 'invalid_payload',
+    message: error instanceof Error ? error.message : 'invalid payload',
+  };
+}
+
+function checkpointDatabase(dbPath: string): void {
+  const db = openDb({ filename: dbPath });
+  try {
+    migrate(db);
+    db.pragma('wal_checkpoint(FULL)');
+  } finally {
+    db.close();
+  }
+}
+
+function writeBackupFile(path: string, header: BackupHeader, ciphertext: Buffer, authTag: Buffer): void {
+  const headerJson = Buffer.from(JSON.stringify(header), 'utf8');
+  const headerLength = Buffer.alloc(HEADER_LENGTH_BYTES);
+  headerLength.writeUInt32BE(headerJson.length, 0);
+  const fd = openSync(path, 'wx', 0o600);
+  try {
+    writeSync(fd, MAGIC);
+    writeSync(fd, headerLength);
+    writeSync(fd, headerJson);
