+    } finally {
+      db.close();
+    }
+  } catch (error) {
+    const message = error instanceof Error ? error.message : 'restore test failed';
+    return recordRestoreTest(sourceDbPath, {
+      backupId,
+      backupFile,
+      result: 'failure',
