+const MAGIC = Buffer.from('FWBKP001');
+const HEADER_LENGTH_BYTES = 4;
+const AUTH_TAG_BYTES = 16;
+const KEY_BYTES = 32;
+const SALT_BYTES = 32;
+const IV_BYTES = 12;
+const MAIN_TABLES = [
+  'business_profiles',
+  'products',
+  'subscription_plans',
+  'orders',
+  'order_items',
+  'invoices',
+  'audit_logs',
+  'backup_history',
