+
+export function createBackup(
+  dbPath: string,
+  passphrase: string,
+  outDir: string,
+  options: CreateBackupOptions = {},
+): BackupHistoryEntry {
+  assertUsablePassphrase(passphrase);
+  if (!existsSync(dbPath)) {
