+
+type BackupKind = 'manual' | 'auto' | 'pre_restore';
+type RestoreTestResult = 'success' | 'failure';
+
+interface BackupPayload {
+  passphrase?: unknown;
+  outDir?: unknown;
+  kind?: unknown;
+  note?: unknown;
+}
+
+interface RestoreTestPayload {
